import emailjs from '@emailjs/browser';

// -------------------------------------------------------
// EmailJS configuration
// Replace these with your real EmailJS credentials:
//   1. Go to https://www.emailjs.com and create a free account
//   2. Create an Email Service (Gmail, Outlook, etc.)
//   3. Create an Email Template for booking confirmations
//   4. Copy your Service ID, Template ID, and Public Key below
// -------------------------------------------------------
const SERVICE_ID = 'YOUR_SERVICE_ID';       // e.g. 'service_abc123'
const TEMPLATE_ID = 'YOUR_TEMPLATE_ID';     // e.g. 'template_xyz456'
const PUBLIC_KEY = 'YOUR_PUBLIC_KEY';       // e.g. 'abcDEFghiJKL'

// Organization email that receives booking notifications
export const ORG_EMAIL = 'bookings@modelvogue.com';

/**
 * Send booking confirmation email to the customer AND
 * a notification email to the organization.
 *
 * @param {Object} bookingData - Booking form data
 * @param {Object} eventData   - Event details
 * @returns {Promise}
 */
export const sendBookingEmail = async (bookingData, eventData) => {
  const templateParams = {
    // Customer info
    to_name: bookingData.name,
    to_email: bookingData.email,
    phone: bookingData.phone,

    // Event info
    event_title: eventData.title,
    event_date: new Date(eventData.date).toLocaleDateString('en-IN', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    }),
    event_time: eventData.time,
    event_location: eventData.location,
    event_category: eventData.category,

    // Booking info
    tickets: bookingData.tickets,
    total_amount: `₹${(eventData.price * bookingData.tickets).toLocaleString('en-IN')}`,
    booking_id: `MVB-${Date.now()}`,
    booking_date: new Date().toLocaleDateString('en-IN'),
    special_requests: bookingData.specialRequests || 'None',

    // Org notification
    org_email: ORG_EMAIL,
  };

  return emailjs.send(SERVICE_ID, TEMPLATE_ID, templateParams, PUBLIC_KEY);
};

/**
 * Send a contact form enquiry to the organization.
 *
 * @param {Object} contactData
 * @returns {Promise}
 */
export const sendContactEmail = async (contactData) => {
  const CONTACT_TEMPLATE_ID = 'YOUR_CONTACT_TEMPLATE_ID'; // separate template for contact form

  const templateParams = {
    from_name: contactData.name,
    from_email: contactData.email,
    phone: contactData.phone,
    subject: contactData.subject,
    message: contactData.message,
    org_email: ORG_EMAIL,
  };

  return emailjs.send(SERVICE_ID, CONTACT_TEMPLATE_ID, templateParams, PUBLIC_KEY);
};
